n    }\n    id = (\"\" + idCard).trim();\n    if (id.matches(\"[0-9]{17}[0-9Xx]\")) {\n        sexText = id.substring(16, 17);\n    } else if (id.matches(\"[0-9]{15}\")) {\n        sexText = id.substring(14, 15);\n    } else {\n        return -1;\n    }\n    sexDigit = java.lang.Integer.parseInt(sexText);\n    return sexDigit % 2 == 0 ? 0 : 1;\n}\n\nfunction regexMatch(text, regex) {\n    if (text == null || regex == null) {\n        return 0;\n    }\n    try {\n        return (\"\" + text).matches(\"\" + regex) ? 1 : 0;\n    } catch (Exception ex) {\n        return 0;\n    }\n}\n\nfunction strLeft(text, n) {\n    if (text == null) {\n        return null;\n    }\n    if (n == null) {\n        return \"\";\n    }\n    s = \"\" + text;\n    limit = n.intValue();\n    if (limit <= 0) {\n        return \"\";\n    }\n    if (s.length() <= limit) {\n        return s;\n    }\n    return s.substring(0, limit);\n}\n\nfunction strRight(text, n) {\n    if (text == null) {\n        return null;\n    }\n    if (n == null) {\n        return \"\";\n    }\n    s = \"\" + text;\n    limit = n.intValue();\n    if (limit <= 0) {\n        return \"\";\n    }\n    len = s.length();\n    if (len <= limit) {\n        return s;\n    }\n    return s.substring(len - limit, len);\n}\n\ncredit_amount = null\nif (score_f1.score >= -999999 && score_f1.score < 0 && age >= -999999 && age < 18) {\n    credit_amount = 0\n} else if (score_f1.score >= -999999 && score_f1.score < 0 && age >= 18 && age < 35) {\n    credit_amount = 0\n} else if (score_f1.score >= -999999 && score_f1.score < 0 && age >= 35 && age < 55) {\n    credit_amount = 0\n} else if (score_f1.score >= -999999 && score_f1.score < 0 && age >= 55) {\n    credit_amount = 0\n} else if (score_f1.score >= 0 && score_f1.score < 250 && age >= -999999 && age < 18) {\n    credit_amount = 0\n} else if (score_f1.score >= 0 && score_f1.score < 250 && age >= 18 && age < 35) {\n    credit_amount = 1000\n} else if (score_f1.score >= 0 && score_f1.score < 250 && age >= 35 && age < 55) {\n    credit_amount = 2000\n} else if (score_f1.score >= 0 && score_f1.score < 250 && age >= 55) {\n    credit_amount = 3000\n} else if (score_f1.score >= 205 && score_f1.score < 350 && age >= -999999 && age < 18) {\n    credit_amount = 0\n} else if (score_f1.score >= 205 && score_f1.score < 350 && age >= 18 && age < 35) {\n    credit_amount = 2000\n} else if (score_f1.score >= 205 && score_f1.score < 350 && age >= 35 && age < 55) {\n    credit_amount = 3000\n} else if (score_f1.score >= 205 && score_f1.score < 350 && age >= 55) {\n    credit_amount = 4000\n} else if (score_f1.score >= 350 && age >= -999999 && age < 18) {\n    credit_amount = 0\n} else if (score_f1.score >= 350 && age >= 18 && age < 35) {\n    credit_amount = 3000\n} else if (score_f1.score >= 350 && age >= 35 && age < 55) {\n    credit_amount = 4000\n} else if (score_f1.score >= 350 && age >= 55) {\n    credit_amount = 5000\n}\n\n_result = {\"credit_amount\": credit_amount}\n_result\n','QLEXPRESS','{\"rowDimensions\":[{\"varCode\":\"score_f1.score\",\"varLabel\":\"欺诈分F1/评分 score\",\"varType\":\"DOUBLE\",\"_varId\":1,\"segments\":[{\"label\":\"[-inf, 0)\",\"operator\":\"range\",\"value\":\"\",\"min\":\"-999999\",\"max\":\"0\"},{\"label\":\"[0, 250)\",\"operator\":\"range\",\"value\":\"\",\"min\":\"0\",\"max\":\"250\"},{\"label\":\"[250, 350)\",\"operator\":\"range\",\"value\":\"\",\"min\":\"205\",\"max\":\"350\"},{\"label\":\"[350, inf)\",\"operator\":\">=\",\"value\":\"350\"}],\"_refType\":\"MODEL_OUTPUT\"}],\"colDimensions\":[{\"varCode\":\"age\",\"varLabel\":\"年龄 age\",\"varType\":\"NUMBER\",\"_varId\":37,\"segments\":[{\"label\":\"[-inf, 18)\",\"operator\":\"range\",\"value\":\"\",\"min\":\"-999999\",\"max\":\"18\"},{\"label\":\"[18, 35)\",\"operator\":\"range\",\"value\":\"\",\"min\":\"18\",\"max\":\"35\"},{\"label\":\"[35, 55)\",\"operator\":\"range\",\"value\":\"\",\"max\":\"55\",\"min\":\"35\"},{\"label\":\"[55, inf)\",\"operator\":\">=\",\"value\":\"55\"}